const Profile = ({
  user,
  updateUser,
  deleteUser,
  setLoggedIn,
  setTriggeredLogout,
}) => {
  const navigator = useNavigate();
  const [formValue, setFormValue] = useState({});
  const [formErrors, setFormErrors] = useState({});
  const [deleteRequest, setDeleteRequest] = useState(false);
  const [editFullName, setEditFullName] = useState(false);
  const [editEmail, setEditEmail] = useState(false);
  const [editGender, setEditGender] = useState(false);
  const [editPassword, setEditPassword] = useState(false);
  const [editPlan, setEditPlan] = useState(false);

  const activateEditField = (fieldName) => {
    if (fieldName === "fullname") {
      setEditFullName(true);
      setEditEmail(false);
      setEditGender(false);
      setEditPassword(false);
    }
    if (fieldName === "email") {
      setEditEmail(true);
      setEditFullName(false);
      setEditGender(false);
      setEditPassword(false);
    }
    if (fieldName === "gender") {
      setEditGender(true);
      setEditFullName(false);
      setEditEmail(false);
      setEditPassword(false);
    }
    if (fieldName === "password") {
      setEditPassword(true);
      setEditFullName(false);
      setEditEmail(false);
      setEditGender(false);
    }
    if (fieldName === "plan") {
      setEditPlan(true);
      setEditPassword(false);
      setEditFullName(false);
      setEditEmail(false);
      setEditGender(false);
    }
  };
  const submitForm = async (e, validationTarget, fieldName) => {
    e.preventDefault();
    const validationErrors = validationTarget(formValue[fieldName]);
    if (Object.keys(validationErrors).length > 0) {
      setFormErrors(validationErrors);
    } else {
      const updated = await updateUser(user.id, {
        [fieldName]: formValue[fieldName],
      });
      if (!updated.success) {
        if (updated.reason === "email") {
          setFormErrors({ email: "Email already exists" });
        }
      } else {
        setFormValue({});
        setFormErrors({});
        handleCancel(fieldName);
        if (fieldName !== "password") {
          setEditPassword(false);
        }
      }
    }
  };

  const handleCancel = (target) => {
    if (target === "fullname") {
      setEditFullName(false);
    }
    if (target === "email") {
      setEditEmail(false);
    }
    if (target === "password") {
      setEditPassword(false);
    }
    if (target === "gender") {
      setEditGender(false);
    }
    if (target === "plan") {
      setEditPlan(false);
    }
    setFormValue({});
    setFormErrors({});
  };

  const handelChange = (e) => {
    const { name, value } = e.target;
    if (name === "email") {
      setFormValue({ ...formValue, email: value.toLowerCase() });
